import { type ReactNode, useMemo } from 'react';
import useResizeObserver from 'use-resize-observer';

import { GridPlotContext } from '../context/GridPlotContext.js';

export const GridPlotSizeProvider = ({ children }: { children: ReactNode }) => {
  const { width = 0, height = 0, ref } = useResizeObserver<HTMLDivElement>();

  const context = useMemo(() => ({ width, height, ref }), [width, height, ref]);

  return (
    <GridPlotContext.Provider value={context}>
      {children}
    </GridPlotContext.Provider>
  );
};

GridPlotSizeProvider['displayName'] = 'GridPlotSizeProvider';
